@extends('layouts.app') @section('title','Crear encuesta') @section('content')<div class="row justify-content-center"><div class="col-lg-8"><h1>Crear encuesta</h1><form class="card p-4" method="post" action="{{ route('admin.store') }}">@csrf<label class="form-label">Título</label><input class="form-control mb-3" name="title" required><label class="form-label">Descripción</label><textarea class="form-control mb-3" name="description"></textarea><div class="form-check mb-4"><input class="form-check-input" type="checkbox" value="1" name="collect_location" id="location"><label class="form-check-label" for="location">Solicitar ubicación al responder</label></div><h2 class="h4">Preguntas</h2><div id="questions"></div><button type="button" class="btn btn-outline-primary my-3" id="add">Agregar pregunta</button><button class="btn btn-primary w-100">Guardar encuesta</button></form></div></div>@endsection @push('scripts')<script>let n=0;const box=document.getElementById('questions');function add(){const i=n++;box.insertAdjacentHTML('beforeend',`<div class="border rounded p-3 mb-3"><button type="button" class="btn-close float-end" onclick="this.parentElement.remove()"></button><label class="form-label">Pregunta</label><input class="form-control mb-2" name="questions[${i}][text]" required><select class="form-select mb-2" name="questions[${i}][type]" onchange="this.nextElementSibling.hidden=this.value!=='multiple_choice'"><option value="text">Respuesta corta</option><option value="paragraph">Párrafo</option><option value="multiple_choice">Opción múltiple</option><option value="scale">Escala (1-5)</option></select><input class="form-control" hidden name="questions[${i}][options]" placeholder="Opciones separadas por coma"></div>`)}document.getElementById('add').onclick=add;add();</script>@endpush
